CREATE VIEW `ads_short_video_bonus_view` (`dt` COMMENT "分区", `Id` COMMENT "赠币表主键", `AccountId` COMMENT "用户表主键id
", `InitValue` COMMENT "初始化赠币数量", `Value` COMMENT "赠币数量", `CreateTime` COMMENT "创建时间", `UpdateTime` COMMENT "上次更新时间", `ExpireTime` COMMENT "过期时间", `IsValid` COMMENT "是否过期 0 否 1 是", `IsEmpty` COMMENT "是否已经用光了", `Source` COMMENT "bonus 来源。默认0-充值获得。取值：1-签到，2-签到卡，3-签到视频，4-看视频任务，5-登录任务，6-看剧任务，7-首次评论，8-绑定邮箱，9-应用好评，10-EDM赠送，11-浏览第三方页面，17-余额激活，100-人工赠送，101-活动签到，102-兑换码，103-活动任务", `regionId` COMMENT "归属区域 id，1：香港，2：北美；")
COMMENT "海剧-赠币表" AS SELECT `ods`.`ods_tidb_short_video_bonus`.`dt`, `ods`.`ods_tidb_short_video_bonus`.`Id`, `ods`.`ods_tidb_short_video_bonus`.`AccountId`, `ods`.`ods_tidb_short_video_bonus`.`InitValue`, `ods`.`ods_tidb_short_video_bonus`.`Value`, `ods`.`ods_tidb_short_video_bonus`.`CreateTime`, `ods`.`ods_tidb_short_video_bonus`.`UpdateTime`, `ods`.`ods_tidb_short_video_bonus`.`ExpireTime`, `ods`.`ods_tidb_short_video_bonus`.`IsValid`, `ods`.`ods_tidb_short_video_bonus`.`IsEmpty`, `ods`.`ods_tidb_short_video_bonus`.`Source`, `ods`.`ods_tidb_short_video_bonus`.`regionId`
FROM `ods`.`ods_tidb_short_video_bonus`;